        }
      `}</style>
    </div>
  );
}

function AccessDenied({ onBack }: { onBack: () => void }) {
  return (
    <div className="fixed inset-0 flex items-center justify-center z-50 px-6 backdrop-blur-md bg-black/40">
      <div className="bg-white rounded-[28px] w-full max-w-sm shadow-[0_20px_60px_-12px_rgba(0,0,0,0.4)] px-8 py-12 text-center animate-fade-up relative overflow-hidden">
        {/* 装饰背景 */}
        <div className="absolute -top-10 -right-10 w-32 h-32 bg-red-50 rounded-full" />
        <div className="absolute -bottom-8 -left-8 w-24 h-24 bg-red-50 rounded-full" />

        {/* 锁图标 - 更有设计感 */}
        <div className="relative w-20 h-20 mx-auto mb-5">
          <div className="absolute inset-0 bg-gradient-to-br from-red-400 to-rose-500 rounded-2xl rotate-12 opacity-20" />
          <div className="relative w-full h-full bg-gradient-to-br from-red-50 to-rose-50 rounded-2xl flex items-center justify-center ring-1 ring-red-200/50">
            <div className="w-12 h-12 bg-gradient-to-br from-red-400 to-rose-500 rounded-xl flex items-center justify-center shadow-lg shadow-red-200/50">
              <Lock className="w-6 h-6 text-white" />
            </div>
          </div>
        </div>

        {/* 文案区域 */}
        <div className="relative space-y-2 mb-8">
          <div className="inline-flex items-center gap-2 mx-auto">
            <span className="w-6 h-px bg-gradient-to-r from-transparent to-red-300" />
            <h2 className="text-xl font-bold text-gray-800 tracking-wide">
              暂无法进入活动
            </h2>
            <span className="w-6 h-px bg-gradient-to-l from-transparent to-red-300" />
          </div>
          <p className="text-sm text-gray-500 leading-relaxed max-w-[240px] mx-auto">
            根据相关规定，未满 18 周岁暂无法参与本次活动。感谢您的理解！
          </p>
        </div>

        {/* 返回按钮 */}
        <button
          onClick={onBack}
          className="group relative w-full bg-gradient-to-r from-green-500 to-emerald-600 text-white font-semibold py-3.5 rounded-xl flex items-center justify-center gap-2 shadow-lg shadow-green-200/50 hover:shadow-xl hover:shadow-green-300/50 hover:-translate-y-0.5 transition-all duration-300 overflow-hidden"
        >
          <span className="absolute inset-0 bg-gradient-to-r from-transparent via-white/15 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-700" />
          <ChevronLeft className="w-4 h-4 group-hover:-translate-x-0.5 transition-transform" />
          返回首页
        </button>
      </div>

      <style>{`
        @keyframes fade-up {
          from { opacity: 0; transform: translateY(24px) scale(0.96); }
          to { opacity: 1; transform: translateY(0) scale(1); }
        }
        .animate-fade-up {
          animation: fade-up 0.4s cubic-bezier(0.16, 1, 0.3, 1);
        }
      `}</style>
    </div>
  );
}

export default function Demo(_props: DemoProps) {
  const [page, setPage] = useState<"confirm" | "loading" | "denied">("confirm");

  if (page === "loading") {
    return <Loading />;
  }

  if (page === "denied") {
    return <AccessDenied onBack={() => setPage("confirm")} />;
  }

  return (
    <AgeConfirmation
      onConfirm={() => setPage("loading")}
      onDeny={() => setPage("denied")}
    />
  );
}

