interface DemoProps {}

export default function Demo(_props: DemoProps) {
  const days = 7;
  const hours = 12;
  const minutes = 30;
  const seconds = 45;

  return (
    <div className="min-h-screen bg-gradient-to-b from-green-50 to-white pb-24">
      {/* 顶部头图 - 更细腻的渐变 + 装饰足球光效 */}
      <div className="relative bg-gradient-to-br from-emerald-500 via-green-500 to-green-700 px-6 pt-12 pb-10 text-white overflow-hidden">
        {/* 装饰光效 */}
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-yellow-300/20 rounded-full blur-3xl" />
        <div className="absolute top-6 left-1/3 w-24 h-24 bg-orange-400/15 rounded-full blur-2xl" />
        <div className="absolute -bottom-8 -left-8 w-32 h-32 bg-emerald-300/20 rounded-full blur-3xl" />
        {/* 装饰足球纹理 */}
        <div className="absolute top-4 right-8 text-6xl opacity-10 select-none">⚽</div>
        <div className="absolute bottom-6 right-4 text-4xl opacity-10 select-none">⚽</div>
        <div className="absolute top-20 left-6 text-3xl opacity-8 select-none">★</div>
        <div className="relative z-10">
          <div className="text-3xl font-bold mb-2">⚽ 世界杯助威盛典</div>
          <div className="text-green-100 text-lg">激情一夏，为热爱加冕</div>
        </div>
      </div>

      {/* 阶段标签 */}
      <div className="flex justify-center -mt-5 mb-6 relative z-10">
        <span className="bg-gradient-to-r from-orange-500 to-orange-400 text-white px-5 py-1.5 rounded-full text-sm font-medium shadow-lg shadow-orange-500/30">
          🔥 预热阶段
        </span>
      </div>

      {/* 倒计时卡片 - 玻璃质感 + 微动效 */}
      <div className="mx-4 mb-6">
        <div className="relative bg-white/80 backdrop-blur-xl rounded-2xl p-5 shadow-lg border border-white/50 overflow-hidden">
          {/* 装饰微光 */}
          <div className="absolute -top-6 -right-6 w-20 h-20 bg-green-400/10 rounded-full blur-xl" />
          <div className="text-center text-gray-500 text-sm mb-3">距离活动开始</div>
          <div className="flex justify-center gap-4">
            {[
              { value: days, label: "天" },
              { value: hours, label: "时" },
              { value: minutes, label: "分" },
              { value: seconds, label: "秒" },
            ].map((item, idx) => (
              <div key={item.label} className="flex flex-col items-center group">
                <div className="w-16 h-16 bg-gradient-to-b from-gray-800 to-gray-900 text-white rounded-xl flex items-center justify-center text-2xl font-bold shadow-md transition-all duration-300 group-hover:scale-105 group-hover:shadow-lg">
                  {String(item.value).padStart(2, "0")}
                </div>
                <span className="text-xs text-gray-400 mt-1.5 font-medium">{item.label}</span>
              </div>
            ))}
          </div>
